userDefinedLinkHintCss:
div>.vimiumHintMarker {
  background: transparent;
  border: 2px solid #cba6f7;
  outline: 1px solid #1e1e2e;
  border-radius: 0;
  padding: 1px 0 0 0;

  & span {
    padding-inline: 2px;
    color: #1e1e2e;
    background-color: #cba6f7;
    font-family: monospace;
    font-size: 11px;
    font-weight: 900;
    text-shadow: none;
  }

  &>.matchingCharacter {
    color: #cba6f7;
    background-color: #1e1e2e;
  }
}

div#hud-container {
  visibility: collapse;
}
